class ExtractedUrls(BaseModel):
    urls: list[str]

class WebpageSummary(BaseModel):
    summary: str

channels = get_channels()

if "general" not in channels:
    raise ValueError("Channel 'general' not found.")

if "random" not in channels:
    raise ValueError("Channel 'random' not found.")

general_messages = read_channel_messages("general")

if len(general_messages) == 0:
    final_message = "I checked #general and found no website links to summarize."
else:
    general_message_data = [message.model_dump() for message in general_messages]

    extracted_urls = query_ai_assistant(
        "You are given Slack messages from the #general channel as structured objects with sender, recipient, and body fields. "
        "Extract every website URL that was posted or shared in the message bodies. "
        "Only include actual webpage links or clearly shared website URLs. "
        "Ignore anything that is not a real link. "
        "Messages: {0}".format(general_message_data),
        ExtractedUrls,
    )

    unique_urls = sorted(set(extracted_urls.urls))

    if len(unique_urls) == 0:
        final_message = "I checked #general and found no website links to summarize."
    else:
        page_records = [{"url": url, "content": get_webpage(url)} for url in unique_urls]

        summarized_pages = [
            {
                "url": record["url"],
                "summary": (
                    "Could not retrieve webpage content."
                    if record["content"] is None or record["content"].strip() == ""
                    else query_ai_assistant(
                        "Summarize this webpage for a Slack post in 1 to 3 concise sentences. "
                        "Focus on the main topic and key points, and ignore boilerplate such as navigation, cookie notices, and footer text when possible.\n"
                        "URL: {0}\n"
                        "Webpage content:\n{1}".format(record["url"], record["content"]),
                        WebpageSummary,
                    ).summary
                ),
            }
            for record in page_records
        ]

        final_message = (
            "Summary of websites posted in #general:\n"
            + "\n".join(
                [
                    "- {0}: {1}".format(page["url"], page["summary"])
                    for page in summarized_pages
                ]
            )
        )

send_channel_message("random", final_message)
print(final_message)
